import{_ as a,C as d,o as r,c as o,E as i,a3 as s}from"./chunks/framework.BVmBWEBf.js";const l="/versions/v0.10.0/screens/devices/m2cv.png",b=JSON.parse('{"title":"M2CV","description":"","frontmatter":{"title":"M2CV","pageClass":"device-doc"},"headers":[],"relativePath":"devices/m2cv.md","filePath":"devices/m2cv.md"}'),n={name:"devices/m2cv.md"};function h(c,t,g,p,m,v){const e=d("DeviceHeading");return r(),o("div",null,[i(e,{slug:"m2cv",title:"M2CV"}),t[0]||(t[0]=s('<p>MIDI to control voltage</p><p><img src="'+l+'" alt="M2CV parameters" class="screen"></p><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><p>Convert MIDI notes or gates to <strong>control voltages</strong> with optional voice-allocation rules.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Use <strong>M2CV</strong> at the <strong>end</strong> of a CV16-equipped rig.</p></div><h2 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h2><div class="device-params-table"><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>What it does</th></tr></thead><tbody><tr><td>Bypass</td><td>0 – 1</td><td>When on, the device is disabled and MIDI passes through unchanged.</td></tr><tr><td>Mode</td><td>0 – 2</td><td>Operating mode for this device (see values below).</td></tr><tr><td>Algo</td><td>0 – 6</td><td>Voice-allocation or routing algorithm (see values below).</td></tr></tbody></table></div><h2 id="parameter-values" tabindex="-1">Parameter values <a class="header-anchor" href="#parameter-values" aria-label="Permalink to &quot;Parameter values&quot;">​</a></h2><h3 id="bypass" tabindex="-1">Bypass <a class="header-anchor" href="#bypass" aria-label="Permalink to &quot;Bypass&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Device is active and processes MIDI.</td></tr><tr><td style="text-align:right;">1</td><td>On</td><td>Device is bypassed; messages pass through unchanged.</td></tr></tbody></table><h3 id="mode" tabindex="-1">Mode <a class="header-anchor" href="#mode" aria-label="Permalink to &quot;Mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Auto</td><td>M2CV: map notes to CV automatically by pitch.</td></tr><tr><td style="text-align:right;">1</td><td>Channel</td><td>M2CV: one CV channel per MIDI channel.</td></tr><tr><td style="text-align:right;">2</td><td>Gate</td><td>M2CV: emit gate/trigger voltages from note on/off.</td></tr></tbody></table><h3 id="algo" tabindex="-1">Algo <a class="header-anchor" href="#algo" aria-label="Permalink to &quot;Algo&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>None</td><td>No voice stealing — one voice per note.</td></tr><tr><td style="text-align:right;">1</td><td>Oldest</td><td>Steal the longest-held voice when poly limit reached.</td></tr><tr><td style="text-align:right;">2</td><td>Newest</td><td>Replace the most recent voice.</td></tr><tr><td style="text-align:right;">3</td><td>Lowest</td><td>Steal the lowest-pitched active voice.</td></tr><tr><td style="text-align:right;">4</td><td>Highest</td><td>Steal the highest-pitched active voice.</td></tr><tr><td style="text-align:right;">5</td><td>Low Vel</td><td>Steal the quietest active voice.</td></tr><tr><td style="text-align:right;">6</td><td>High Vel</td><td>Steal the loudest active voice.</td></tr></tbody></table>',14))])}const y=a(n,[["render",h]]);export{b as __pageData,y as default};
